#include <stdio.h>
#include <stdlib.h>
#define INF 1000000000
#define MAXN 100005
typedef struct Edge {
    int v, w;
    struct Edge* next;
} Edge;
Edge* edges[MAXN];
int dist[MAXN];
int prev[MAXN];
void dijkstra(int n, int s) {
    for (int i = 1; i <= n; i++) {
        dist[i] = INF;
        prev[i] = -1;
    }
    dist[s] = 0;
    Edge** pq = (Edge**)malloc((n + 1) * sizeof(Edge*));
    int pqSize = 0;
    pq[pqSize++] = (Edge*)malloc(sizeof(Edge));
    pq[pqSize - 1]->v = s;
    pq[pqSize - 1]->w = 0;
    while (pqSize > 0) {
        int u = pq[0]->v;
        Edge* temp = pq[0];
        pq[0] = pq[pqSize - 1];
        pqSize--;
        free(temp);
        for (Edge* e = edges[u]; e != NULL; e = e->next) {
            int v = e->v;
            int w = e->w;
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                prev[v] = u;
                pq[pqSize++] = (Edge*)malloc(sizeof(Edge));
                pq[pqSize - 1]->v = v;
                pq[pqSize - 1]->w = dist[v];
            }
        }
    }
    free(pq);
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        for (int i = 1; i <= n; i++) {
            edges[i] = NULL;
        }
        for (int i = 0; i < m; i++) {
            int a, b, w;
            scanf("%d %d %d", &a, &b, &w);
            Edge* e = (Edge*)malloc(sizeof(Edge));
            e->v = b;
            e->w = w;
            e->next = edges[a];
            edges[a] = e;
            e = (Edge*)malloc(sizeof(Edge));
            e->v = a;
            e->w = w;
            e->next = edges[b];
            edges[b] = e;
        }
        dijkstra(n, 1);
        if (dist[n] == INF) {
            printf("-1\n");
        } else {
            int u = n;
            while (u != -1) {
                printf("%d ", u);
                u = prev[u];
            }
            printf("\n");
        }
    }
    return 0;
}

