#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;
typedef pair<int, int> pii;
const int INF = 1000000000;
const int MAXN = 100005;
vector<pii> edges[MAXN];
int dist[MAXN];
int prev[MAXN];
void dijkstra(int n, int s) {
    for (int i = 1; i <= n; i++) {
        dist[i] = INF;
        prev[i] = -1;
    }
    dist[s] = 0;
    priority_queue<pii, vector<pii>, greater<pii>> pq;
    pq.push({0, s});
    while (!pq.empty()) {
        int u = pq.top().second;
        int d = pq.top().first;
        pq.pop();
        if (d > dist[u]) continue;
        for (auto e : edges[u]) {
            int v = e.first;
            int w = e.second;
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                prev[v] = u;
                pq.push({dist[v], v});
            }
        }
    }
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int t;
    cin >> t;
    while (t--) {
        int n, m;
        cin >> n >> m;
        for (int i = 0; i < m; i++) {
            int a, b, w;
            cin >> a >> b >> w;
            edges[a].push_back({b, w});
            edges[b].push_back({a, w});
        }
        dijkstra(n, 1);
        if (dist[n] == INF) {
            cout << -1 << endl;
        } else {
            int u = n;
            while (u != -1) {
                cout << u << ' ';
                u = prev[u];
            }
            cout << endl;
        }
    }
    return 0;
}

