import java.util.PriorityQueue;
import java.util.Scanner;
public class Main {
    static final int INF = 1000000000;
    static final int MAXN = 100005;
    static int[] dist = new int[MAXN];
    static int[] prev = new int[MAXN];
    static class Edge implements Comparable<Edge> {
        int v, w;
        Edge(int v, int w) {
            this.v = v;
            this.w = w;
        }
        public int compareTo(Edge other) {
            return Integer.compare(w, other.w);
        }
    }
    static void dijkstra(int n, int s) {
        for (int i = 1; i <= n; i++) {
            dist[i] = INF;
            prev[i] = -1;
        }
        dist[s] = 0;
        PriorityQueue<Edge> pq = new PriorityQueue<>();
        pq.add(new Edge(s, 0));
        while (!pq.isEmpty()) {
            int u = pq.poll().v;
            for (Edge e : edges[u]) {
                int v = e.v;
                int w = e.w;
                if (dist[v] > dist[u] + w) {
                    dist[v] = dist[u] + w;
                    prev[v] = u;
                    pq.add(new Edge(v, dist[v]));
                }
            }
        }
    }
    static Edge[][] edges = new Edge[MAXN][];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int m = sc.nextInt();
            for (int i = 0; i < m; i++) {
                int a = sc.nextInt();
                int b = sc.nextInt();
                int w = sc.nextInt();
                if (edges[a] == null) edges[a] = new Edge[0];
                Edge[] temp = new Edge[edges[a].length + 1];
                System.arraycopy(edges[a], 0, temp, 0, edges[a].length);
                temp[edges[a].length] = new Edge(b, w);
                edges[a] = temp;
                if (edges[b] == null) edges[b] = new Edge[0];
                temp = new Edge[edges[b].length + 1];
                System.arraycopy(edges[b], 0, temp, 0, edges[b].length);
                temp[edges[b].length] = new Edge(a, w);
                edges[b] = temp;
            }
            dijkstra(n, 1);
            if (dist[n] == INF) {
                System.out.println(-1);
            } else {
                int u = n;
                while (u != -1) {
                    System.out.print(u + ' ');
                    u = prev[u];
                }
                System.out.println();
            }
        }
    }
}

