const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const INF = 1000000000;
const MAXN = 100005;
let dist = new Array(MAXN + 1).fill(INF);
let prev = new Array(MAXN + 1).fill(-1);
let edges = new Array(MAXN + 1).fill(0).map(() => []);
function dijkstra(n, s) {
    dist[s] = 0;
    let pq = [[s, 0]];
    while (pq.length > 0) {
        pq.sort((a, b) => a[1] - b[1]);
        let [u, d] = pq.shift();
        if (d > dist[u]) continue;
        for (let [v, w] of edges[u]) {
            if (dist[v] > dist[u] + w) {
                dist[v] = dist[u] + w;
                prev[v] = u;
                pq.push([v, dist[v]]);
            }
        }
    }
}
let t = parseInt(input[idx].trim());
idx++;
while (t--) {
    let [n, m] = input[idx].trim().split(' ').map(Number);
    idx++;
    for (let i = 0; i < m; i++) {
        let [a, b, w] = input[idx].trim().split(' ').map(Number);
        edges[a].push([b, w]);
        edges[b].push([a, w]);
        idx++;
    }
    dijkstra(n, 1);
    if (dist[n] == INF) {
        console.log(-1);
    } else {
        let u = n;
        while (u != -1) {
